import React, { useEffect } from 'react';
import { useAnalytics } from '../hooks/useAnalytics';
import styles from './AnalyticsBar.module.css';

const StatCard = ({ label, value, color, icon }) => (
  <div className={styles.statCard} style={{ '--stat-color': color }}>
    <div className={styles.statIcon}>{icon}</div>
    <div className={styles.statValue}>{value ?? '—'}</div>
    <div className={styles.statLabel}>{label}</div>
    <div className={styles.statGlow} />
  </div>
);

export default function AnalyticsBar({ refreshTrigger }) {
  const { analytics, loading, fetchAnalytics } = useAnalytics();

  useEffect(() => { fetchAnalytics(); }, [fetchAnalytics, refreshTrigger]);

  return (
    <div className={styles.wrapper}>
      <div className={styles.header}>
        <h2 className={styles.title}>Overview</h2>
        {analytics && (
          <div className={styles.progressBar}>
            <div className={styles.progressLabel}>{analytics.completionPercentage}% complete</div>
            <div className={styles.track}>
              <div className={styles.fill} style={{ width: `${analytics.completionPercentage}%` }} />
            </div>
          </div>
        )}
      </div>

      {loading && !analytics ? (
        <div className={styles.loadingRow}>
          {[...Array(5)].map((_, i) => <div key={i} className={styles.skeleton} />)}
        </div>
      ) : (
        <div className={styles.statsGrid}>
          <StatCard label="Total" value={analytics?.total} color="var(--text-dim)"
            icon={<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="14" y="14" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/></svg>}
          />
          <StatCard label="Completed" value={analytics?.completed} color="var(--success)"
            icon={<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><polyline points="20 6 9 17 4 12"/></svg>}
          />
          <StatCard label="In Progress" value={analytics?.inProgress} color="var(--info)"
            icon={<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>}
          />
          <StatCard label="Pending" value={analytics?.pending} color="var(--warning)"
            icon={<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>}
          />
          <StatCard label="Overdue" value={analytics?.overdue} color="var(--danger)"
            icon={<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"/><line x1="12" y1="9" x2="12" y2="13"/><line x1="12" y1="17" x2="12.01" y2="17"/></svg>}
          />
        </div>
      )}
    </div>
  );
}
